graph = {'A':['B','C'],'B':['D'],'C':['E'],'D':[],'E':[]}
queue = deque(['A'])
visited = []
while queue:
    node = queue.popleft()
    if node not in visited:
        visited.append(node)
        queue.extend(graph[node])
print(visited)

