S4.starter:
import heapq

graph = {'A':[('B',2),('C',5)],'B':[('D',4)],'C':[('D',1)],'D':[]}
frontier = [(0,'A')]
while frontier:
    cost,node = heapq.heappop(frontier)
    print(node,cost)
    if node == 'D':
        break
    for nxt,w in graph[node]:
        heapq.heappush(frontier,(cost+w,nxt))

